const data = $input.first().json;
const passes = data.passes || [];
const now = new Date();

// Find passes within the next 30 minutes that are actually visible (peak alt > 20°)
const upcoming = passes.filter(p => {
  if (!p.rise || p.rise === 'Check Heavens-Above.com') return false;
  if (!p.visible) return false;
  if ((p.peak_alt || 0) < 20) return false;

  // Try to parse rise time — format like "Thu Jun 19 09:30 PM"
  try {
    const riseDate = new Date(p.rise);
    const diffMin = (riseDate - now) / 60000;
    return diffMin > 0 && diffMin <= 30;
  } catch (e) {
    return false;
  }
});

if (upcoming.length === 0) {
  return [{ json: { send: false } }];
}

const pass = upcoming[0];
const lines = [
  `🛸 *ISS VISIBLE PASS ALERT!*`,
  ``,
  `The International Space Station is passing overhead in less than 30 minutes!`,
  ``,
  `🚀 *Rise:* ${pass.rise}`,
  `📍 *Set:* ${pass.set}`,
  `📐 *Peak altitude:* ${pass.peak_alt}° ${pass.peak_az || ''}`,
  ``,
  `👀 Look ${pass.peak_az || 'S'} — it will appear as a bright moving star, no blinking!`,
  ``,
  `_No telescope needed — naked eye or binoculars_`,
  `_Tip: ISS moves from horizon to horizon in ~6 minutes_`,
];

return [{ json: { send: true, text: lines.join('\n') } }];
